use std::fmt::Write;

use crate::gate_config::GateConfig;
use crate::stats::{MetricStats, PercentileSummary, compute_summaries};

use super::config_keys::{python_config_key, rust_config_key};
use super::defaults_append::{append_python_defaults, append_rust_defaults};

pub struct GenerateConfigParams<'a> {
    pub py: &'a MetricStats,
    pub rs: &'a MetricStats,
    pub py_n: usize,
    pub rs_n: usize,
    pub gate: &'a GateConfig,
}

pub fn generate_config_toml_by_language(p: &GenerateConfigParams<'_>) -> String {
    let mut out = String::from(
        "# Generated by kiss mimic\n# Thresholds based on max values of analyzed codebase\n\n",
    );
    let _ = writeln!(out, "[gate]");
    let _ = writeln!(
        out,
        "test_coverage_threshold = {}",
        p.gate.test_coverage_threshold
    );
    let _ = writeln!(out, "min_similarity = {}", p.gate.min_similarity);
    let _ = writeln!(out, "duplication_enabled = {}", p.gate.duplication_enabled);
    let _ = writeln!(
        out,
        "orphan_module_enabled = {}\n",
        p.gate.orphan_module_enabled
    );
    if p.py_n > 0 {
        append_section(
            &mut out,
            "[python]",
            &compute_summaries(p.py),
            python_config_key,
        );
    } else {
        append_python_defaults(&mut out);
    }
    if p.rs_n > 0 {
        append_section(&mut out, "[rust]", &compute_summaries(p.rs), rust_config_key);
    } else {
        append_rust_defaults(&mut out);
    }
    out
}

pub fn append_section(
    out: &mut String,
    header: &str,
    sums: &[PercentileSummary],
    key_fn: fn(&str) -> Option<&'static str>,
) {
    out.push_str(header);
    out.push('\n');
    for s in sums {
        if let Some(k) = key_fn(s.metric_id) {
            let _ = writeln!(out, "{k} = {}", s.max);
        }
    }
    out.push('\n');
}
